request.zodSource:
z.object({
  pairingCode: z.string().min(1),
  deviceName: z.string().min(1).optional(),
  clientDeviceId: z.string().regex(/^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i),
})

z.object({
  worktreePath: z.string().min(1, 'Worktree path is required'),
  branchName: z.string().min(1, 'Branch name is required'),
})

z.object({
  baseBranch: z.string().min(1, 'Base branch is required'),
  branchName: branchNameSchema,
})

z.object({
  baseBranch: z.string().min(1, 'Base branch is required'),
  branchName: branchNameSchema,
})

z.object({
    effort: z.enum(EFFORT_VALUES).nullable().optional(),
    fast: z.boolean().nullable().optional(),
    ultracode: z.boolean().nullable().optional(),
    adaptiveThinking: z.boolean().nullable().optional(),
  })

z.object({
  chatId: z.string(),
  message: z.string().min(1, 'Commit message cannot be empty'),
  files: z.array(z.string()),
})

z.object({
  chatId: z.string().optional(),
  path: z.string().min(1),
  content: z.string(),
})

z.object({
  chatId: z.string().optional(),
  file: z.string().optional(),
  oldPath: z.string().optional(),
  // Validated (rejects a non-git source with 400) but not branched on — this
  // endpoint only serves git, and the response hardcodes source: 'git'.
  source: z.enum(['git']).optional(),
  base: z.string().optional(),
})

z.object({
  q: z.string().min(2, 'Query must be at least 2 characters'),
  path: z.string().min(1, 'path is required'),
  chatId: z.string().optional(),
  includeIgnored: z.string().optional(),
})

z
  .object({ rename: z.string().optional(), color: ColorSchema.optional() })
  .refine((v) => v.rename !== undefined || v.color !== undefined, {
    message: 'rename or color required',
  })

z.object({
  inputs: z.record(z.string(), z.unknown()).optional(),
  payload: z.unknown().optional(),
})
